			cin >> c;

			if (c == '%') {

				g.x = i, g.y = j;

			}

			else if (c == '@') {

				s.x = i, s.y = j;

				a[i][j] = 0;

				q.push_back(s);

			}

			else if (c == '$') {

				sol.push_back(P(i, j));

				a[i][j] = -1;

			}

			else if (c == '#') {

				a[i][j] = -1;

			}

		}

	}

	bool res = false;

	while (!q.empty()) {

