					a[tx][ty] = -1;

					tsol.push_back(P(tx, ty));

				}

			}

		}

		for (auto p : q) {

			for (int i = 0; i < 4; i++) {

				int tx = p.x + dx[i], ty = p.y + dy[i];

				if (tx >= 0 && tx < H && ty >= 0 && ty < W && a[tx][ty] == 1) {

					if (tx == g.x && ty == g.y) {

						res = true;

						tq.clear();

						break;

					}

					a[tx][ty] = 0;

					tq.push_back(P(tx, ty));

				}

			}

		}

		q = tq, sol = tsol;

	}

	cout << (res ? "Yes" : "No") << endl;

	return 0;

}

